UPDATE DATA
SET    DATA_NM = #{dataNm},
       DATA_CN = #{dataCn},
       DATA_TYPE = #{dataType},
       DATA_SHARE_YN = #{dataShareYn}

       , FILE_ID = #{fileId}

WHERE  DATA_NO = #{dataNo}

UPDATE FILE_DETAIL
SET    FILE_ID = #{newFileId}
WHERE  FILE_ID = #{oldFileId}

UPDATE DATA
SET    DATA_DEL_YN = 1, DATA_DEL_DT = SYSDATE
WHERE  DATA_NO = #{dataNo}

UPDATE DATA
SET    DATA_CNT = DATA_CNT + 1
WHERE  DATA_NO = #{dataNo}
